#include<bits/stdc++.h>
using namespace std;
int kp[10001];
int n;
int main()
{
	int t;
	scanf("%d",&t);
	while(t--)
	{
		scanf("%d",&n);
		for(int i=1;i<=n;i++)
		{
			scanf("%d",&kp[i]);
		}
		int flag=0;
		for(int i=1;i<=n;i++)
		{
			if(kp[i]==0)
			{
				printf("yes\n");
				flag=1;
				break;
			} 
			else
			{
				flag=0;
			}
		}
		if(flag==0)
		{
			printf("no\n");
		}
	}
	return 0;
}
